        assert!(reg.is_command("/help"));
        assert!(reg.is_command("help"));
        assert!(reg.is_command("exit"));
        assert!(reg.is_command("quit"));
        assert!(reg.is_command("/model"));
        assert!(reg.is_command("/clear"));
