/// Handles `/lint` with automatic fallback to the last written files when no arg is given.
pub(crate) async fn handle_lint_with_fallback(session: &mut ChatSession, args: &str) {
    let t = ui::theme::active();
    if args.is_empty() {

        if session.code_out.last_files.is_empty() && session.code_out.last_files_written.is_empty() {
            println!(
                "{} no files to lint. Generate code first.",
                ui::theme::paint_warning(&t, "\u{258C}")
            );
        } else {
            let paths: Vec<String> = if !session.code_out.last_files_written.is_empty() {
                session
                    .code_out
                    .last_files_written
                    .iter()
                    .filter(|p| p.path.exists())
                    .map(|p| p.path.display().to_string())
                    .collect()
            } else {
                session
                    .code_out
                    .last_files
                    .iter()
                    .filter(|f| !f.path.is_empty())
                    .map(|f| {
                        let base = session
                            .ctx
                            .project_dir
                            .clone()
                            .unwrap_or_else(|| std::env::current_dir().unwrap_or_default());
                        crate::types::resolve_safe_path(&base, &f.path)
                            .filter(|p| p.exists())
                            .map(|p| p.display().to_string())
                            .unwrap_or_else(|| f.path.clone())
                    })
                    .collect()
            };
            for p in paths {
                handle_lint(session, &p).await;
            }
        }
    } else {
        handle_lint(session, args).await;
    }
}

/// Searches for text in project files (`/find` command).
pub(crate) fn handle_find(session: &ChatSession, query: &str) {
    let t = ui::theme::active();
    if query.is_empty() {
        println!("{}", ui::theme::paint_rail_empty(&t));
        println!(
            "{} {}",
            ui::theme::paint(&t, "accent", "\u{258C}", true),
            ui::theme::paint_bright(&t, "usage: /find <query>")
        );
        println!(
            "{}  {}",
            ui::theme::paint(&t, "accent", "\u{258C}", true),
            ui::theme::paint_dim(
                &t,
                "search text inside the project (skips node_modules, target, .git, ...)"
            )
        );
        println!("{}", ui::theme::paint_rail_empty(&t));
        return;
    }

    let root = session
        .ctx
        .project_dir
        .clone()
        .unwrap_or_else(|| std::env::current_dir().unwrap_or_default());

    let report = find_matches(&root, query, &FindOptions::default());

    println!("{}", ui::theme::paint_rail_empty(&t));
    println!(
        "{} {}",
        ui::theme::paint(&t, "accent", "\u{258C}", true),
        ui::theme::paint_bright(&t, &format!("\u{203a} FIND  {}", query)),
    );
    println!(

        "{} {} {}",
        ui::theme::paint(&t, "accent", "\u{258C}", true),
        ui::theme::paint_dim(&t, "in"),
        ui::theme::paint_bright(&t, &format!("{}", root.display()))
    );
    println!("{}", ui::theme::paint_rail_empty(&t));

    if report.matches.is_empty() {
        println!(
            "{} {}",
            ui::theme::paint(&t, "accent", "\u{258C}", true),
            ui::theme::paint_warning(&t, "(no matches)")
        );
        println!("{}", ui::theme::paint_rail_empty(&t));
        return;
    }

    let show_limit = 50usize;
    let shown = report.matches.len().min(show_limit);

    let find_body = format_find_matches(&t, &root, &report.matches, show_limit);
    if shown > 40 {
        maybe_page(&find_body);
    } else {
        print!("{}", find_body);
    }

    let unique_files: std::collections::BTreeSet<String> = report
        .matches
        .iter()
        .map(|m| {
            m.path
                .strip_prefix(&root)
                .map(|p| p.to_string_lossy().replace('\\', "/"))
                .unwrap_or_else(|_| m.path.display().to_string())
        })
        .collect();

    let mut summary = format!(
        "  {} match{} in {} file{} · scanned {} · skipped {} · {}ms",
        report.matches.len(),
        if report.matches.len() == 1 { "" } else { "es" },
        unique_files.len(),
        if unique_files.len() == 1 { "" } else { "s" },
        report.files_scanned,
        report.files_skipped,
        report.elapsed_ms,
    );
    if report.truncated {
        summary.push_str("  (truncated)");
    }
    if shown < report.matches.len() {
        summary.push_str(&format!("  (showing first {})", shown));
    }
    println!("{}", ui::theme::paint_rail_empty(&t));
    println!("{}", ui::theme::paint_success_label(&t, &summary));
    println!("{}", ui::theme::paint_rail_empty(&t));
}

/// Formats find match results into a display string (deduplicates paths, formats line/col).
fn format_find_matches(
    t: &ui::theme::Theme,
    root: &std::path::Path,
    matches: &[crate::find::Match],
    show_limit: usize,
) -> String {
    let mut buf = String::new();
    let mut last_path: Option<String> = None;
    for m in matches.iter().take(show_limit) {
        let rel = m
            .path
            .strip_prefix(root)
            .map(|p| p.to_string_lossy().replace('\\', "/"))
            .unwrap_or_else(|_| m.path.display().to_string());
        if last_path.as_deref() != Some(rel.as_str()) {
            if last_path.is_some() {
                buf.push_str(&format!("{}\n", ui::theme::paint_rail_empty(t)));
            }
            buf.push_str(&format!(
                "{} {}\n",
                ui::theme::paint(t, "accent", "\u{258C}", true),
                ui::theme::paint(

                    t,
                    "accent_info",
                    &format!("\u{2500}\u{2500} {} \u{2500}\u{2500}", rel),
                    true
                ),
            ));
            last_path = Some(rel);
        }
        let line_no_w = 4usize;
        let col_w = 3usize;
        buf.push_str(&format!(
            "{} {}   {:>lw$}:{:<cw$}  {}\n",
            ui::theme::paint(t, "accent", "\u{258C}", true),
            ui::theme::paint_dim(t, "\u{251c}\u{2500}\u{2500}"),
            m.line_no,
            m.column,
            ui::theme::paint_bright(t, &trim_for_display(&m.line, 120)),
            lw = line_no_w,
            cw = col_w
        ));
    }
    buf.push_str(&format!("{}\n", ui::theme::paint_rail_empty(t)));
    buf
}

/// Truncates a string to a max number of characters for display.
fn trim_for_display(s: &str, max: usize) -> String {
    if s.chars().count() <= max {
        s.to_string()
    } else {
        let mut out: String = s.chars().take(max.saturating_sub(1)).collect();
        out.push('\u{2026}');
        out
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn trim_for_display_short_string() {
        assert_eq!(trim_for_display("hello", 10), "hello");
    }

    #[test]
    fn trim_for_display_exact_fit() {
        assert_eq!(trim_for_display("hello", 5), "hello");
    }

    #[test]
    fn trim_for_display_truncates_with_ellipsis() {
        let result = trim_for_display("hello world", 5);
        assert_eq!(result.chars().count(), 5);
        assert!(result.ends_with('\u{2026}'));
    }

    #[test]
    fn trim_for_display_empty_string() {
        assert_eq!(trim_for_display("", 5), "");
    }

    #[test]
    fn trim_for_display_max_zero() {
        let result = trim_for_display("hello", 0);
        assert_eq!(result, "\u{2026}");
    }

    #[test]
    fn trim_for_display_unicode_preserved() {
        let input = "héllo wörld";
        let result = trim_for_display(input, 20);
        assert_eq!(result, input);
    }

    #[test]
    fn trim_for_display_unicode_truncated() {
        let input = "héllo wörld 👍";
        let result = trim_for_display(input, 6);
        assert_eq!(result.chars().count(), 6);
        assert!(result.ends_with('\u{2026}'));
    }
}

use std::path::Path;

use rustyline::completion::{Completer, Pair};
use rustyline::highlight::Highlighter;
use rustyline::hint::Hinter;
use rustyline::validate::{ValidationContext, ValidationResult, Validator};
use rustyline::{Context, Helper};

#[derive(Default)]
pub(crate) struct RemHelper;

impl Completer for RemHelper {
    type Candidate = Pair;

    fn complete(&self, line: &str, pos: usize, _ctx: &Context<'_>) -> rustyline::Result<(usize, Vec<Pair>)> {
        let line_before = &line[..pos];

        if let Some(at_pos) = line_before.rfind('@') {
            let prefix = &line_before[at_pos + 1..];
            if prefix.starts_with("http") {
                return Ok((0, vec![]));
            }
            return Ok(complete_path(at_pos + 1, prefix));
        }

        if !line_before.contains(' ') && line_before.starts_with('/') {
            let reg = crate::commands::registry();
            let names = reg.command_names();
            let candidates: Vec<Pair> = names
                .iter()
                .filter(|n| n.starts_with(line_before))
                .map(|n| Pair {
                    replacement: n.to_string(),
                    display: n.to_string(),
                })
                .collect();
            return Ok((0, candidates));
        }

        // Tab-complete file paths after /session export and /session import
        for prefix_cmd in &["/session export ", "/session import "] {
            if let Some(tail) = line_before.strip_prefix(*prefix_cmd) {
                return Ok(complete_path(prefix_cmd.len(), tail));
            }
        }

        Ok((0, vec![]))
    }
}

fn complete_path(start_pos: usize, prefix: &str) -> (usize, Vec<Pair>) {
    let (dir, partial) = if prefix.is_empty() || prefix.ends_with('/') {
        (Path::new(if prefix.is_empty() { "." } else { prefix }), "")
    } else {
        let path = Path::new(prefix);
        let d = path
            .parent()
            .filter(|p| !p.as_os_str().is_empty())
            .unwrap_or_else(|| Path::new("."));
        let p = path.file_name().and_then(|s| s.to_str()).unwrap_or("");
        (d, p)
    };

    let dir_prefix = if prefix.is_empty() || prefix.ends_with('/') {
        prefix.to_string()
    } else {
        let parent = Path::new(prefix).parent().and_then(|p| p.to_str()).unwrap_or("");
        if parent.is_empty() {
            String::new()
        } else {
            format!("{}/", parent)
        }
    };

    let Ok(entries) = std::fs::read_dir(dir) else {
        return (start_pos, vec![]);
    };

    let mut candidates = Vec::new();
    for entry in entries.flatten() {
        let name = entry.file_name();
        let name_str = name.to_string_lossy().into_owned();
        if !name_str.starts_with(partial) {

            continue;
        }
        let is_dir = entry.file_type().map(|t| t.is_dir()).unwrap_or(false);
        let display = format!("{}{}{}", dir_prefix, name_str, if is_dir { "/" } else { "" });
        candidates.push(Pair {
            replacement: display.clone(),
            display,
        });
    }

    (start_pos, candidates)
}

impl Hinter for RemHelper {
    type Hint = String;

    fn hint(&self, line: &str, pos: usize, _ctx: &Context<'_>) -> Option<String> {
        let line_before = &line[..pos];

        if line_before.starts_with('/') && !line_before.contains(' ') {
            let reg = crate::commands::registry();
            let names = reg.command_names();
            let matches: Vec<&&str> = names.iter().filter(|n| n.starts_with(line_before)).collect();
            if matches.len() == 1 {
                let hint = matches[0][line_before.len()..].to_string();
                if !hint.is_empty() {
                    return Some(hint);
                }
            }
        }

        None
    }
}

impl Validator for RemHelper {
    fn validate(&self, _ctx: &mut ValidationContext<'_>) -> rustyline::Result<ValidationResult> {
        Ok(ValidationResult::Valid(None))
    }
}

impl Highlighter for RemHelper {}

impl Helper for RemHelper {}

//! Configuration loading, saving, and provider construction.
//! Reads `~/.config/rem-cli/config.toml` and `.remcli.toml`, merges them into
//! an [`AppConfig`], and builds the appropriate [`Provider`] from config values.

use crate::cli::{AppConfig, PartialConfig};
use crate::provider::{Provider, ProviderKind};
use crate::ui;
use anyhow::{Context, Result};
use std::collections::BTreeMap;
use std::fs;
use std::io::{self, Write};
use std::path::{Path, PathBuf};
use std::sync::LazyLock;
use std::sync::RwLock;
use tracing::warn;

/// Cached config to avoid repeated TOML parsing from disk.
static CONFIG_CACHE: LazyLock<RwLock<Option<AppConfig>>> = LazyLock::new(|| RwLock::new(None));

/// Returns the cached config, or `None` if not yet loaded.
pub(crate) fn get_cached_config() -> Option<AppConfig> {
    CONFIG_CACHE.read().unwrap_or_else(|e| e.into_inner()).clone()
}

/// Returns the config directory path, checking XDG_CONFIG_HOME first.
pub(crate) fn config_dir() -> Option<std::path::PathBuf> {
    if let Ok(xdg) = std::env::var("XDG_CONFIG_HOME") {
        let dir = std::path::PathBuf::from(xdg).join("rem-cli");
        return Some(dir);
    }
    dirs::home_dir().map(|h| h.join(".config/rem-cli"))
}

/// Saves config to XDG config dir or `~/.config/rem-cli/config.toml`.
/// Updates the in-memory cache directly to avoid unnecessary re-reads.
pub(crate) fn save_config(cfg: &AppConfig) -> Result<()> {
    let text = toml::to_string_pretty(cfg).context("failed to serialize config")?;
    if let Some(dir) = config_dir() {
        fs::create_dir_all(&dir)?;
        let path = dir.join("config.toml");
        let tmp_path = dir.join("config.toml.tmp");
        fs::write(&tmp_path, &text).context("failed to write config")?;
        fs::rename(&tmp_path, &path).context("failed to atomically replace config")?;
    }
    // Update cache directly instead of invalidating, to avoid re-reading from disk
    crate::pager::init_page_threshold(cfg.page_threshold);
    let mut cache = CONFIG_CACHE.write().unwrap_or_else(|e| e.into_inner());
    *cache = Some(cfg.clone());
    Ok(())
}

/// Interactive first-time setup that prompts for a workspace directory.
pub(crate) fn first_run_setup(cfg: &mut AppConfig) -> Result<Option<PathBuf>> {
    let t = ui::theme::active();
    println!();
    println!(
        "{} {}",
        ui::theme::paint(&t, "accent", "Welcome to REM!", true),
        ui::theme::paint_dim(&t, "first-time setup")
    );
    println!();
    println!("{}", ui::theme::paint(&t, "accent", "\u{258C}", true));
    println!(
        "{} {}",
        ui::theme::paint(&t, "accent", "\u{258C}", true),
        ui::theme::paint_bright(&t, "Where should REM create your projects?"),
    );
    println!(
        "{} e.g. {} or {}",

        ui::theme::paint(&t, "accent", "\u{258C}", true),
        ui::theme::paint_bright(&t, "~/projects"),
        ui::theme::paint_bright(&t, "/home/you/code")
    );
    println!(
        "{} type {} for current dir, or a full path",
        ui::theme::paint(&t, "accent", "\u{258C}", true),
        ui::theme::paint_bright(&t, ".")
    );
    println!("{}", ui::theme::paint(&t, "accent", "\u{258C}", true));
    print!("{}", ui::theme::paint(&t, "accent", "\u{258C}  rem> ", true));
    let _ = io::stdout().flush();

    let mut input = String::new();
    io::stdin().read_line(&mut input)?;
    let trimmed = input.trim();

    let dir = if trimmed.is_empty() || trimmed == "." {
        std::env::current_dir().unwrap_or_default()
    } else if trimmed == "~" {
        dirs::home_dir().unwrap_or_else(|| PathBuf::from("~"))
    } else if trimmed.starts_with("~/") {
        if let Some(home) = dirs::home_dir() {
            home.join(trimmed.trim_start_matches("~/"))
        } else {
            PathBuf::from(trimmed)
        }
    } else {
        PathBuf::from(trimmed)
    };

    if !dir.exists() {
        println!(
            "{} creating {}...",
            ui::theme::paint(&t, "accent", "\u{258C}", true),
            dir.display()
        );
        fs::create_dir_all(&dir)?;
    }

    cfg.workspace_dir = Some(dir.to_string_lossy().to_string());
    save_config(cfg)?;

    println!(
        "{} workspace saved to {}",
        ui::theme::paint_success_label(&t, "\u{258C}  ✓"),
        ui::theme::paint_bright(&t, &dir.display().to_string())
    );
    println!(
        "{} change it anytime with {}",
        ui::theme::paint(&t, "accent", "\u{258C}", true),
        ui::theme::paint_bright(&t, "/dir <path>")
    );
    println!();

    Ok(Some(dir))
}

/// Loads and merges global (XDG_CONFIG_HOME or `~/.config/rem-cli/config.toml`) and local (`.remcli.toml`) config.
/// Results are cached in a global [`CONFIG_CACHE`] to avoid repeated TOML parsing.
pub(crate) fn load_config() -> Result<AppConfig> {
    {
        let cache = CONFIG_CACHE.read().unwrap_or_else(|e| e.into_inner());
        if let Some(ref cached) = *cache {
            return Ok(cached.clone());
        }
    }
    let mut cfg = AppConfig::default();
    if let Some(dir) = config_dir() {
        let path = dir.join("config.toml");
        if path.exists() {
            let text = fs::read_to_string(&path).with_context(|| format!("failed to read {}", path.display()))?;
            let partial: PartialConfig = toml::from_str(&text).context("invalid global config")?;
            cfg.apply_partial(partial);
        }
    }
    let local = PathBuf::from(".remcli.toml");
    if local.exists() {

        let text = fs::read_to_string(&local).with_context(|| format!("failed to read {}", local.display()))?;
        let partial: PartialConfig = toml::from_str(&text).context("invalid local config")?;
        cfg.apply_partial(partial);
    }
    crate::pager::init_page_threshold(cfg.page_threshold);
    let mut cache = CONFIG_CACHE.write().unwrap_or_else(|e| e.into_inner());
    *cache = Some(cfg.clone());
    Ok(cfg)
}

/// Builds a [`Provider`] from config, resolving API keys and model defaults.
/// Per-provider overrides from `config.providers` are merged on top of global values.
pub(crate) fn build_provider(cfg: &AppConfig, system_prompt: String) -> Result<Provider> {
    let kind = ProviderKind::from_str(&cfg.provider);
    let pcfg = cfg.providers.get(kind.as_str());

    // Helper macro to avoid repeated pcfg.and_then patterns
    macro_rules! pget {
        ($field:ident) => {
            pcfg.and_then(|p| p.$field.clone())
        };
        (copy $field:ident) => {
            pcfg.and_then(|p| p.$field)
        };
    }

    let timeout_s = pget!(copy timeout_s).unwrap_or(cfg.timeout_s);
    let model = resolve_model(kind, pget!(model).unwrap_or_else(|| cfg.model.clone()));
    let model_ctx = pget!(copy model_ctx).unwrap_or(cfg.model_ctx);

    let base_url = pget!(api_url)
        .or_else(|| cfg.api_url.clone())
        .unwrap_or_else(|| crate::provider::default_base_url(kind));

    let api_key = pget!(api_key)
        .or_else(|| cfg.api_key.clone())
        .or_else(|| resolve_api_key_from_env(kind));

    let key_empty = api_key.as_ref().is_none_or(|k| k.is_empty());
    if key_empty {
        if let Some(env_var) = crate::provider::api_key_env_var(kind) {
            eprintln!(
                "{} provider '{}' requires --api-key or {}",
                ui::theme::paint_warning(&ui::theme::active(), "warning:"),
                kind.as_str(),
                env_var,
            );
        }
    }

    let mut provider = Provider::new(kind, base_url, model, timeout_s, system_prompt, api_key, model_ctx);

    // Per-provider reasoning override (user can mark any model as reasoning)
    if let Some(true) = pget!(copy reasoning_model) {
        provider.reasoning_config.enabled = true;
    }
    if let Some(effort) = &cfg.reasoning_effort {
        provider.reasoning_config.effort = crate::reasoning::ReasoningEffort::from_str(effort);
        provider.reasoning_config.enabled = true;
    }
    if let Some(budget) = cfg.thinking_budget {
        provider.reasoning_config.thinking_budget = budget;
    }
    Ok(provider)
}

/// Resolves the model name, using provider defaults when the user model is a placeholder.
fn resolve_model(kind: ProviderKind, model: String) -> String {

    if model == "rem-coder:latest" || model == "rem-coder" {
        crate::provider::default_model(kind).unwrap_or(&model).to_string()
    } else {
        model
    }
}

/// Cached resolved API keys from environment variables.
static API_KEY_CACHE: LazyLock<RwLock<BTreeMap<&'static str, Option<String>>>> =
    LazyLock::new(|| RwLock::new(BTreeMap::new()));

/// Resolves the API key from the appropriate environment variable for the provider kind.
/// Results are cached since environment variables don't change at runtime.
fn resolve_api_key_from_env(kind: ProviderKind) -> Option<String> {
    let var = crate::provider::api_key_env_var(kind)?;
    {
        let cache = API_KEY_CACHE.read().unwrap_or_else(|e| e.into_inner());
        if let Some(cached) = cache.get(var) {
            return cached.clone();
        }
    }
    let val = std::env::var(var).ok().filter(|v| !v.is_empty());
    let mut cache = API_KEY_CACHE.write().unwrap_or_else(|e| e.into_inner());
    cache.insert(var, val.clone());
    val
}

type SystemPromptCache = RwLock<Option<(Option<String>, String)>>;

/// Cached system prompt to avoid repeated disk reads.
static SYSTEM_PROMPT: LazyLock<SystemPromptCache> = LazyLock::new(|| RwLock::new(None));

/// Loads the system prompt from file, falling back to the built-in default.
pub(crate) fn load_system_prompt(custom_prompts_dir: Option<&str>) -> String {
    {
        let cache = SYSTEM_PROMPT.read().unwrap_or_else(|e| e.into_inner());
        if let Some((ref cached_dir, ref content)) = *cache {
            if *cached_dir == custom_prompts_dir.map(|s| s.to_string()) {
                return content.clone();
            }
        }
    }
    let content = load_system_prompt_uncached(custom_prompts_dir);
    let mut cache = SYSTEM_PROMPT.write().unwrap_or_else(|e| e.into_inner());
    *cache = Some((custom_prompts_dir.map(|s| s.to_string()), content.clone()));
    content
}

fn load_system_prompt_uncached(custom_prompts_dir: Option<&str>) -> String {
    let mut candidates = Vec::new();
    if let Some(dir) = custom_prompts_dir {
        candidates.push(PathBuf::from(dir).join("system_prompt.txt"));
    }
    candidates.push(PathBuf::from("prompts/system_prompt.txt"));
    // Per-project system prompt override via `.rem/system_prompt.md`
    candidates.push(PathBuf::from(".rem/system_prompt.md"));
    for path in candidates {
        if path.exists() {
            if let Ok(text) = fs::read_to_string(path) {
                let trimmed = text.trim();
                if !trimmed.is_empty() {
                    return trimmed.to_string();
                }
            }
        }
    }
    crate::constants::DEFAULT_SYSTEM_PROMPT.to_string()
}

fn warn_missing_api_key(cfg: &AppConfig) {

    let kind = ProviderKind::from_str(&cfg.provider);
    if let Some(env_var) = crate::provider::api_key_env_var(kind) {
        let has_key =
            cfg.api_key.as_ref().is_some_and(|k| !k.is_empty()) || std::env::var(env_var).is_ok_and(|k| !k.is_empty());
        if !has_key {
            let t = ui::theme::active();
            let warn_prefix = ui::theme::paint_warning(&t, "config warning:");
            let msg = format!("provider '{}' may need --api-key or {}", cfg.provider, env_var);
            warn!("{msg}");
            eprintln!("  {} {msg}", warn_prefix);
        }
    }
}

/// Validates config at startup. Returns `Err` for hard failures (invalid provider, mode, URL),
/// prints warnings for non-critical issues (missing API key, unusual timeouts, etc.).
pub(crate) fn validate_config(cfg: &AppConfig) -> Result<()> {
    let known_providers = [
        "ollama",
        "openai",
        "vllm",
        "anthropic",
        "gemini",
        "azure",
        "bedrock",
        "openrouter",
        "deepseek",
        "github",
        "xai",
    ];
    let t = ui::theme::active();
    let warn_prefix = ui::theme::paint_warning(&t, "config warning:");

    if !known_providers.contains(&cfg.provider.as_str()) {
        let msg = format!(
            "unknown provider '{}'. Known: {}",
            cfg.provider,
            known_providers.join(", ")
        );
        return Err(anyhow::anyhow!("{}", msg));
    }

    warn_missing_api_key(cfg);

    let mode = cfg.mode.to_uppercase();
    if !["CHAT", "CODE", "PLAN"].contains(&mode.as_str()) {
        let msg = format!("unknown mode '{}' in config. Expected CHAT, CODE, or PLAN.", cfg.mode);
        return Err(anyhow::anyhow!("{}", msg));
    }

    if cfg.timeout_s < 5 || cfg.timeout_s > 600 {
        let msg = format!("timeout_s={} seems unusual (expected 5-600)", cfg.timeout_s);
        warn!("{msg}");
        eprintln!("  {} {msg}", warn_prefix);
    }

    if cfg.model_ctx < 512 {
        let msg = format!(
            "model_ctx={} is very low (< 512). Responses may be truncated.",
            cfg.model_ctx
        );
        warn!("{msg}");
        eprintln!("  {} {msg}", warn_prefix);
    }

    let url = cfg.ollama_url.trim();
    if url.is_empty() || (!url.starts_with("http://") && !url.starts_with("https://")) {
        let msg = format!(
            "ollama_url '{}' does not look like a valid URL (expected http:// or https://)",
            url
        );
        return Err(anyhow::anyhow!("{}", msg));
    }

    if let Some(ref effort) = cfg.reasoning_effort {
        let valid = ["low", "medium", "high"];
        if !valid.contains(&effort.to_lowercase().as_str()) {
            let msg = format!("unknown reasoning_effort '{}'. Expected low, medium, or high", effort);

            warn!("{msg}");
            eprintln!("  {} {msg}", warn_prefix);
        }
    }

    if cfg.thinking_budget == Some(0) {
        let msg = "thinking_budget is 0 — it should be > 0 to have any effect";
        warn!("{msg}");
        eprintln!("  {} {msg}", warn_prefix);
    }

    let theme_name = cfg.theme.to_uppercase();
    let known_themes = ui::theme::list_names();
    if !known_themes.iter().any(|t| t.eq_ignore_ascii_case(&theme_name)) {
        let msg = format!(
            "unknown theme '{}'. Known themes: {}",
            cfg.theme,
            known_themes.join(", ")
        );
        warn!("{msg}");
        eprintln!("  {} {msg}", warn_prefix);
    }

    if cfg.provider.to_lowercase() == "ollama" && cfg.api_key.as_ref().is_some_and(|k| !k.is_empty()) {
        let msg = "api_key is set but provider is 'ollama' — Ollama does not need an API key";
        warn!("{msg}");
        eprintln!("  {} {msg}", warn_prefix);
    }

    Ok(())
}

/// Invalidates the in-memory config cache so the next call to load_config re-reads from disk.
pub(crate) fn invalidate_config_cache() {
    if let Ok(mut cache) = CONFIG_CACHE.write() {
        *cache = None;
    }
}

/// Persists the workspace directory to config.
pub(crate) fn persist_workspace(dir: &Path) {
    let t = ui::theme::active();
    let mut cfg = match load_config() {
        Ok(c) => c,
        Err(e) => {
            eprintln!(
                "  {} failed to load config, not saving workspace: {}",
                ui::theme::paint_error_label(&t, "✗"),
                e
            );
            return;
        }
    };
    cfg.workspace_dir = Some(dir.to_string_lossy().to_string());
    if let Err(e) = save_config(&cfg) {
        eprintln!(
            "  {} failed to save workspace config: {}",
            ui::theme::paint_error_label(&t, "✗"),
            e
        );
    }
}

