//! In-project text search (`/find` command).
//! Walks the project tree with `walkdir`, reads each file with a size cap,
//! and returns every line matching the query. Skips hidden/build/lock dirs.

use std::collections::{HashMap, VecDeque};
use std::fs;
use std::io::BufRead;
use std::path::{Path, PathBuf};
use std::sync::LazyLock;
use std::sync::Mutex;
use std::time::Instant;

use ignore::WalkBuilder;

/// A single hit in a single file.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Match {
    pub path: PathBuf,
    pub line_no: usize,
    pub column: usize,
    pub line: String,
}

/// Knobs for `find_matches`. All fields have sensible defaults; pass
/// `FindOptions::default()` to use them.
#[derive(Debug, Clone)]
pub struct FindOptions {
    pub max_results: usize,
    pub max_file_bytes: u64,
    pub max_depth: usize,
    pub case_sensitive: bool,
    pub use_regex: bool,
}

impl Default for FindOptions {
    fn default() -> Self {
        Self {
            max_results: crate::constants::FIND_MAX_RESULTS,
            max_file_bytes: crate::constants::FIND_MAX_FILE_BYTES,
            max_depth: crate::constants::FIND_MAX_DEPTH,
            case_sensitive: true,
            use_regex: false,
        }
    }
}

/// Result of a `/find` call — matches plus simple summary fields the
/// REPL can render (`handle_find` in `main.rs`).
#[derive(Debug, Clone)]
pub struct FindReport {
    pub matches: Vec<Match>,
    pub files_scanned: usize,
    pub files_skipped: usize,
    pub elapsed_ms: u128,
    pub truncated: bool,
}

/// Directory or file names that should never be descended into. These
/// are excluded at the `walkdir` iterator level so the search stays
/// fast and the output stays focused on source.
pub const SKIP_NAMES: &[&str] = &[
    ".git",
    "node_modules",
    "target",
    "dist",
    "build",
    ".next",
    ".cache",
    ".rem",
    "__pycache__",
    ".venv",
    "venv",
];

/// File suffixes that are always skipped even outside the above dirs.
pub const SKIP_SUFFIXES: &[&str] = &[
    ".min.js", ".min.css", ".lock", ".png", ".jpg", ".jpeg", ".gif", ".webp", ".ico", ".pdf", ".zip", ".tar", ".gz",
    ".bz2", ".xz", ".7z", ".mp3", ".mp4", ".mov", ".woff", ".woff2", ".ttf", ".otf", ".eot",
];

const REGEX_CACHE_MAX_SIZE: usize = 64;

static REGEX_CACHE: LazyLock<Mutex<HashMap<String, regex::Regex>>> = LazyLock::new(|| Mutex::new(HashMap::new()));
static REGEX_CACHE_ORDER: LazyLock<Mutex<VecDeque<String>>> = LazyLock::new(|| Mutex::new(VecDeque::new()));

/// Checks whether a directory name should be skipped during traversal.
pub fn should_skip_dir(name: &str) -> bool {
    SKIP_NAMES.contains(&name)
}

/// Checks whether a file name should be skipped (minified assets, binaries, etc.).

pub fn should_skip_file(name: &str) -> bool {
    let lower_bytes = name.as_bytes();
    let len = lower_bytes.len();
    // Fast path: check common minified extensions using byte comparison
    if len > 7 {
        let end = &lower_bytes[len.saturating_sub(7)..];
        if end.eq_ignore_ascii_case(b".min.js") || end.eq_ignore_ascii_case(b".min.css") {
            return true;
        }
    }
    SKIP_SUFFIXES.iter().any(|suf| {
        let sufb = suf.as_bytes();
        len >= sufb.len() && lower_bytes[len - sufb.len()..].eq_ignore_ascii_case(sufb)
    })
}

/// Walk `root` and return every line whose contents contain `query`.
///
/// By default `query` is matched as a plain substring — no regex metacharacters
/// are interpreted. Set `opts.use_regex = true` to enable regex matching.
/// An empty `query` is treated as "no matches" rather
/// than matching every line, which would be useless.
pub fn find_matches(root: &Path, query: &str, opts: &FindOptions) -> FindReport {
    let start = Instant::now();
    let mut report = FindReport {
        matches: Vec::new(),
        files_scanned: 0,
        files_skipped: 0,
        elapsed_ms: 0,
        truncated: false,
    };

    if query.is_empty() {
        report.elapsed_ms = start.elapsed().as_millis();
        return report;
    }

    let needle: Vec<u8> = if opts.case_sensitive {
        query.as_bytes().to_vec()
    } else {
        query.to_lowercase().into_bytes()
    };

    let regex_pattern: Option<regex::Regex> = if opts.use_regex {
        let re_query = if opts.case_sensitive {
            query.to_string()
        } else {
            format!("(?i){}", query)
        };
        let mut cache = REGEX_CACHE.lock().unwrap_or_else(|e| e.into_inner());
        let mut order = REGEX_CACHE_ORDER.lock().unwrap_or_else(|e| e.into_inner());
        if let Some(re) = cache.get(&re_query) {
            Some(re.clone())
        } else {
            if cache.len() >= REGEX_CACHE_MAX_SIZE {
                if let Some(oldest) = order.pop_front() {
                    cache.remove(&oldest);
                }
            }
            match regex::Regex::new(&re_query) {
                Ok(re) => {
                    cache.insert(re_query.clone(), re.clone());
                    order.push_back(re_query);
                    Some(re)
                }
                Err(e) => {
                    eprintln!(
                        "  {} invalid regex pattern: {}",
                        crate::ui::theme::paint_error_label(&crate::ui::theme::active(), "error:"),
                        e
                    );
                    report.elapsed_ms = start.elapsed().as_millis();
                    return report;
                }
            }
        }
    } else {
        None
    };

let walker = WalkBuilder::new(root)
    .max_depth(Some(opts.max_depth))
    .follow_links(false)
    .git_ignore(true)
    .git_global(true)
    .git_exclude(true)
    .filter_entry(move |e| {
        if e.depth() == 0 {
            return true;
        }
        if e.file_type().map(|t| t.is_dir()).unwrap_or(false) {
            if let Some(name) = e.file_name().to_str() {
                if should_skip_dir(name) {
                    return false;
                }
            }
        }
        if e.file_type().map(|t| t.is_file()).unwrap_or(false) {
            if let Some(name) = e.file_name().to_str() {
                if should_skip_file(name) {
                    return false;
                }
            }
        }
        true
    })
    .build();

for entry in walker.filter_map(|e| e.ok()) {
    if !entry.file_type().map(|t| t.is_file()).unwrap_or(false) {
        continue;
    }

    let path = entry.path();
    if path.file_name().and_then(|n| n.to_str()).is_none() {
        report.files_skipped += 1;
        continue;
    }

    let size = match fs::metadata(path) {
        Ok(m) => m.len(),
        Err(_) => {
            report.files_skipped += 1;
            continue;
        }
    };
    if size == 0 || size > opts.max_file_bytes {
        report.files_skipped += 1;
        continue;
    }

    let file = match std::fs::File::open(path) {
        Ok(f) => f,
        Err(_) => {
            report.files_skipped += 1;
            continue;
        }
    };
    report.files_scanned += 1;
    let reader = std::io::BufReader::new(file);

    if let Some(ref re) = regex_pattern {
        for (idx, raw_line) in reader.lines().map_while(Result::ok).enumerate() {
            let line_no = idx + 1;
            if re.is_match(&raw_line) {
                for cap in re.find_iter(&raw_line) {
                    let column = byte_to_column(&raw_line.as_bytes()[..cap.start()]);
                    report.matches.push(Match {
                        path: path.to_path_buf(),
                        line_no,
                        column: column + 1,
                        line: raw_line.clone(),
                    });
                    if report.matches.len() >= opts.max_results {
                        report.truncated = true;
                        report.elapsed_ms = start.elapsed().as_millis();
                        return report;
                    }
                }
            }
        }
    } else {

            for (idx, raw_line) in reader.lines().map_while(Result::ok).enumerate() {
                let line_no = idx + 1;
                let mut search_from = 0usize;
                let haystack: &[u8];
                let lower_buf: Vec<u8>;
                if opts.case_sensitive {
                    haystack = raw_line.as_bytes();
                } else {
                    lower_buf = raw_line.to_lowercase().into_bytes();
                    haystack = &lower_buf;
                }
                // SAFETY: haystack borrows from lower_buf in the same scope —
                // both are declared inside the for-loop iteration and cannot
                // outlive each other. The borrow checker guarantees this.
                while let Some(pos) = find_subslice(&haystack[search_from..], &needle) {
                    let column = byte_to_column(&haystack[..search_from + pos]);
                    report.matches.push(Match {
                        path: path.to_path_buf(),
                        line_no,
                        column: column + 1,
                        line: raw_line.clone(),
                    });
                    if report.matches.len() >= opts.max_results {
                        report.truncated = true;
                        report.elapsed_ms = start.elapsed().as_millis();
                        return report;
                    }
                    search_from += pos + needle.len();
                    if search_from > haystack.len() {
                        break;
                    }
                }
            }
        }
    }

    report.elapsed_ms = start.elapsed().as_millis();
    report
}

fn find_subslice(haystack: &[u8], needle: &[u8]) -> Option<usize> {
    if needle.is_empty() || haystack.len() < needle.len() {
        return None;
    }
    memchr::memmem::find(haystack, needle)
}

fn byte_to_column(prefix: &[u8]) -> usize {
    let mut count = 0;
    let mut i = 0;
    while i < prefix.len() {
        let b = prefix[i];
        count += 1;
        i += if b < 0x80 {
            1
        } else if b < 0xE0 {
            2
        } else if b < 0xF0 {
            3
        } else {
            4
        };
    }
    count
}

