pub(crate) static CTRL_C_COUNT: AtomicU8 = AtomicU8::new(0);
pub(crate) static SHOULD_EXIT: AtomicBool = AtomicBool::new(false);
/// Set to true when the REPL loop is active so the global handler defers
/// counting to the REPL's own handler (prevents double-counting).
pub(crate) static REPL_ACTIVE: AtomicBool = AtomicBool::new(false);

/// Registers a global Ctrl+C handler that cancels streams on first press,
/// and signals graceful exit on second press.
/// When REPL_ACTIVE is set, the global handler ONLY sets STREAM_CANCELLED
/// without touching CTRL_C_COUNT — the REPL handler manages counting
/// locally via its own `interrupted_once` flag, eliminating the TOCTOU race
/// between the two handlers reading/writing the same atomic.
fn setup_global_ctrlc_handler() {
    tokio::spawn(async {
        let mut consecutive_errors: u32 = 0;
        loop {
            match tokio::signal::ctrl_c().await {
                Ok(()) => {
                    consecutive_errors = 0;
                    provider::STREAM_CANCELLED.store(true, Ordering::SeqCst);
                    // When REPL is active, the REPL handler owns counting via
                    // a local flag in read_user_input — never touch CTRL_C_COUNT.
                    if REPL_ACTIVE.load(Ordering::SeqCst) {
                        continue;
                    }
                    let count = CTRL_C_COUNT.fetch_add(1, Ordering::SeqCst) + 1;
                    if count >= 2 {
                        SHOULD_EXIT.store(true, Ordering::SeqCst);
                    }
                }
                Err(e) => {
                    consecutive_errors += 1;
                    tracing::error!("ctrl-c handler error (count={}): {}", consecutive_errors, e);

                    let delay_ms = [100u64, 200, 400, 1000][(consecutive_errors as usize).saturating_sub(1).min(3)];
                    tokio::time::sleep(std::time::Duration::from_millis(delay_ms)).await;
                }
            }
        }
    });
}

/// Resets the Ctrl+C state (called before entering the REPL loop).
pub(crate) fn reset_ctrlc_count() {
    CTRL_C_COUNT.store(0, Ordering::SeqCst);
    SHOULD_EXIT.store(false, Ordering::SeqCst);
    crate::provider::STREAM_CANCELLED.store(false, Ordering::SeqCst);
}

/// Returns `true` if the user pressed Ctrl+C twice and wants to exit.
pub(crate) fn exit_requested() -> bool {
    SHOULD_EXIT.load(Ordering::SeqCst)
}

// ── Entry point ────────────────────────────────────────────────────────────

fn init_tracing() {
    use tracing_subscriber::filter::EnvFilter;
    let filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("warn"));
    tracing_subscriber::fmt()
        .with_env_filter(filter)
        .with_target(false)
        .compact()
        .init();
}

#[tokio::main]
async fn main() -> Result<()> {
    init_tracing();
    setup_global_ctrlc_handler();

    let cli = Cli::parse();
    let verbose = cli.verbose;

    let mut cfg = match load_config() {
        Ok(c) => c,
        Err(e) => {
            tracing::warn!("failed to load config, using defaults: {e}");
            crate::cli::AppConfig::default()
        }
    };
    if let Some(m) = cli.model {
        cfg.model = m;
    }
    if let Some(url) = cli.ollama_url {
        cfg.ollama_url = url;
    }
    if let Some(p) = cli.provider {
        cfg.provider = p;
    }
    if let Some(k) = cli.api_key {
        cfg.api_key = Some(k);
    }

    if let Err(e) = validate_config(&cfg) {
        let t = theme::active();
        eprintln!(
            "{} {}",
            theme::paint_error_label(&t, "✗"),
            theme::paint(&t, "error", &format!("config error: {e}"), false)
        );
        std::process::exit(1);
    }

    // Commands that don't need a provider — handle early
    let _handled = matches!(
        cli.command,
        Some(Commands::New(_)) | Some(Commands::Index(_)) | Some(Commands::Pull(_))
    );
    if let Some(Commands::New(args)) = cli.command {
        return run_new(args, &cfg);
    }
    if let Some(Commands::Index(args)) = cli.command {
        return run_index(args, &cfg).await;
    }
    if let Some(Commands::Pull(args)) = cli.command {
        return run_pull(args, &cfg);
    }

    let system_prompt = load_system_prompt(cfg.prompts_dir.as_deref());
    let mut client = build_provider(&cfg, system_prompt)?;
    match client.list_models().await {

        Ok(models) => {
            let model_set: HashSet<&str> = models.iter().map(|s| s.as_str()).collect();
            if !model_set.contains(cfg.model.as_str()) {
                let fallback = models.first().cloned().unwrap_or_else(|| cfg.model.clone());
                let t = theme::active();
                eprintln!(
                    "{} model '{}' not found; using '{}'",
                    theme::paint_warning(&t, "warning:"),
                    cfg.model,
                    fallback
                );
                client.set_model(fallback);
            }
        }
        Err(e) => {
            let t = theme::active();
            eprintln!("{} could not list models: {}", theme::paint_warning(&t, "warning:"), e);
        }
    }

    check_system_resources();

    match cli.command {
        Some(Commands::Ask(args)) => run_ask(&client, &cfg, args, verbose).await,
        Some(Commands::Explain(args)) => run_explain(&client, args).await,
        Some(Commands::Patch(args)) => run_patch(&client, &cfg, args).await,
        Some(Commands::Theme(args)) => run_theme(args),
        Some(Commands::New(_)) | Some(Commands::Pull(_)) | Some(Commands::Index(_)) => {
            unreachable!("New/Pull/Index handled by early return before client creation")
        }
        None => {
            let is_pipe = !std::io::stdin().is_terminal();
            if is_pipe {
                let max_pipe = crate::constants::PIPE_INPUT_MAX_BYTES;
                let mut stdin_data = String::with_capacity(max_pipe.min(64_000));
                if std::io::stdin()
                    .take(max_pipe as u64)
                    .read_to_string(&mut stdin_data)
                    .is_ok()
                {
                    if stdin_data.len() >= max_pipe {
                        let t = ui::theme::active();
                        eprintln!(
                            "{} input truncated at {} (use files for larger input)",
                            ui::theme::paint_warning(&t, "warning:"),
                            crate::text_util::human_size(max_pipe as u64)
                        );
                    }
                    let trimmed = stdin_data.trim();
                    if !trimmed.is_empty() {
                        return run_pipe(&client, &cfg, trimmed, verbose).await;
                    }
                }
                // Pipe was empty — exit cleanly instead of starting REPL with no stdin
                return Ok(());
            }
            repl::run_chat(&mut client, &mut cfg, verbose).await
        }
    }
}

//! Project memory persistence.
//! Manages a `.rem/memory.md` file per project for long-term context that
//! persists across chat sessions. Includes starter generation per language.

use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use fs2::FileExt;
use walkdir::WalkDir;

/// Filename for project memory (`.rem/memory.md`).
pub const MEMORY_FILENAME: &str = ".rem/memory.md";

/// Per-project memory stored in `.rem/memory.md`.
pub struct ProjectMemory {
    pub path: PathBuf,
    pub content: String,
    pub loaded: bool,
}

impl ProjectMemory {
    /// Loads project memory from `.rem/memory.md` in the project directory.
    pub fn load(project_dir: &Path) -> Self {
        let path = project_dir.join(MEMORY_FILENAME);
        if path.exists() {
            match fs::read_to_string(&path) {
                Ok(content) if !content.trim().is_empty() => {
                    return Self {
                        path,
                        content,
                        loaded: true,
                    };
                }
                _ => {}
            }
        }
        Self {
            path,
            content: String::new(),
            loaded: false,
        }
    }

    /// Writes the memory content to disk with exclusive file locking.
    pub fn save(&self) -> Result<()> {
        if let Some(parent) = self.path.parent() {
            fs::create_dir_all(parent).context("failed to create .rem directory")?;
        }
        let file = std::fs::OpenOptions::new()
            .write(true)
            .create(true)
            .truncate(true)
            .open(&self.path)
            .context("failed to open memory file for writing")?;
        file.lock_exclusive()
            .context("failed to acquire exclusive lock on memory file")?;
        let result = fs::write(&self.path, &self.content).context("failed to write memory file");
        let _ = file.unlock();
        result
    }

    /// Replaces the memory content with new text.
    pub fn set(&mut self, content: &str) -> Result<()> {
        self.content = content.to_string();
        self.loaded = true;
        self.save()
    }

    /// Appends text to the memory content.
    pub fn append(&mut self, text: &str) -> Result<()> {
        if !self.content.is_empty() {
            self.content.push('\n');
        }
        self.content.push_str(text);
        self.loaded = true;
        self.save()
    }

    /// Returns the memory formatted as context for the LLM prompt.
    pub fn as_context(&self) -> String {
        if self.content.is_empty() {
            return String::new();
        }
        format!("[Project memory from {}]:\n\n{}\n\n", MEMORY_FILENAME, self.content)
    }

/// Generates a starter memory file with project overview and language conventions.
pub fn generate_starter(project_dir: &Path, project_type: &str) -> String {
    let project_name = project_dir
        .file_name()
        .map(|n| n.to_string_lossy().to_string())
        .unwrap_or_else(|| "project".to_string());
    let path_display = project_dir.display();

    let mut memory = format!(
        "# {}\n\n## Project Overview\n- Path: `{}`\n- Type: {}\n\n",
        project_name, path_display, project_type
    );

    let mut files_count = 0usize;
    let mut dirs_count = 0usize;
    for entry in WalkDir::new(project_dir)
        .follow_links(false)
        .max_depth(4)
        .into_iter()
        .filter_entry(|e| {
            let name = e.file_name().to_string_lossy();
            if e.depth() == 0 {
                return true;
            }
            if e.file_type().is_dir() {
                !name.starts_with('.') && !crate::find::should_skip_dir(&name)
            } else {
                !name.starts_with('.')
            }
        })
        .filter_map(|e| e.ok())
    {
        if entry.file_type().is_dir() && entry.depth() > 0 && entry.depth() <= 2 {
            dirs_count += 1;
        } else if entry.file_type().is_file() && entry.depth() > 0 {
            files_count += 1;
        }
    }

    memory.push_str(&format!(
        "## Stats\n{} files, {} directories\n\n",
        files_count, dirs_count
    ));

    memory.push_str("## Conventions\n");

    match project_type {
        "rust" => {
            memory.push_str("- Use `cargo build` / `cargo test` / `cargo run`\n");
            memory.push_str("- Prefer `&str` over `String` where possible\n");
            memory.push_str("- Run `cargo fmt` and `cargo clippy` before committing\n");
        }
        "go" => {
            memory.push_str("- Use `go build` / `go test` / `go run`\n");
            memory.push_str("- Follow standard library patterns and `gofmt`\n");
        }
        "python" => {
            memory.push_str("- Use `pip install` for dependencies\n");
            memory.push_str("- Follow PEP 8, use type hints\n");
            memory.push_str("- Run `pytest` for testing, `ruff` for linting\n");
        }
        "javascript" => {
            memory.push_str("- Use `npm` or `yarn` for dependencies\n");
            memory.push_str("- Prefer ES modules, include `package.json` deps\n");
            memory.push_str("- Run `npm test` or `npm run lint` before committing\n");
        }
        "html_css" => {

                memory.push_str("- Use semantic HTML tags\n");
                memory.push_str("- Responsive CSS with flexbox/grid, mobile-first\n");
                memory.push_str("- Open `index.html` in browser to preview\n");
            }
            "cpp" => {
                memory.push_str("- Use `make` or `cmake` for builds\n");
                memory.push_str("- Show compilation commands with output files\n");
            }
            "dart" => {
                memory.push_str("- Use `pub get` for dependencies\n");
                memory.push_str("- Follow Effective Dart guidelines\n");
            }
            _ => {
                memory.push_str("- Add project conventions here\n");
            }
        }

        memory.push_str("\n## Build & Test Commands\n");
        match project_type {
            "rust" => memory.push_str("- Build: `cargo build`\n- Test: `cargo test`\n"),
            "go" => memory.push_str("- Build: `go build`\n- Test: `go test ./...`\n"),
            "python" => memory.push_str("- Run: `python main.py`\n- Test: `pytest`\n"),
            "javascript" => memory.push_str("- Build: `npm run build`\n- Test: `npm test`\n"),
            "html_css" => memory.push_str("- Preview: open `index.html` in browser\n"),
            "cpp" => memory.push_str("- Build: `make`\n- Test: `make test`\n"),
            "dart" => memory.push_str("- Run: `dart run`\n- Test: `dart test`\n"),
            _ => memory.push_str("- Add build/test commands here\n"),
        }

        memory.push_str("\n## Notes\n- Add project notes here\n");
        memory
    }
}

