#[test]
fn concurrent_append_does_not_corrupt() {
    use std::sync::Arc;
    let dir = std::env::temp_dir().join(format!("rem-test-concur-{}", std::process::id()));
    let _ = fs::create_dir_all(&dir);
    let mem = Arc::new(std::sync::Mutex::new(ProjectMemory::load(&dir)));
    // Ensure initial content
    {
        let mut m = mem.lock().unwrap();
        m.set("initial").unwrap();
    }
    let mem_clone = Arc::clone(&mem);
    let handle = std::thread::spawn(move || {
        let mut m = mem_clone.lock().unwrap();
        m.append("from thread").unwrap();
    });
    {
        let mut m = mem.lock().unwrap();
        m.append("from main").unwrap();

        }
        handle.join().unwrap();
        let m = mem.lock().unwrap();
        let content = fs::read_to_string(&m.path).unwrap();
        assert!(content.contains("initial"), "initial content preserved");
        assert!(content.contains("from"), "content from at least one writer present");
        let _ = fs::remove_dir_all(&dir);
    }
}

use std::io::Write;
use std::process::{Command, Stdio};
use std::sync::LazyLock;
use std::sync::RwLock;

/// Stores the last output text for the `/page` command.
static LAST_OUTPUT: LazyLock<RwLock<String>> = LazyLock::new(|| RwLock::new(String::new()));

/// Stores text for later retrieval via the `/page` command.
pub fn store_output(text: &str) {
    if let Ok(mut buf) = LAST_OUTPUT.write() {
        *buf = text.to_string();
    }
}

/// Returns the stored output for the `/page` command.
pub fn last_output() -> String {
    LAST_OUTPUT.read().map(|b| b.clone()).unwrap_or_default()
}

/// Displays the last stored output through the pager (`/page` command).
pub fn handle_page() {
    let text = last_output();
    if text.is_empty() {
        let t = crate::ui::theme::active();
        eprintln!(
            "{} no previous output stored",
            crate::ui::theme::paint_warning(&t, "\u{258C}")
        );
        return;
    }
    maybe_page(&text);
}

/// Threshold for auto-paging (lines). Output shorter than this is printed directly.
/// Initialized to 50 by default; can be overridden via config or `init_page_threshold`.
static PAGE_THRESHOLD: LazyLock<RwLock<usize>> = LazyLock::new(|| RwLock::new(50));

/// Initialize the page threshold from config. Should be called at startup.
pub fn init_page_threshold(threshold: usize) {
    let mut t = PAGE_THRESHOLD.write().unwrap_or_else(|e| e.into_inner());
    *t = threshold;
}

/// Prints text to stdout, optionally piping through `less` if it's long
/// and a pager is available.
pub fn maybe_page(text: &str) {
    let threshold = *PAGE_THRESHOLD.read().unwrap_or_else(|e| e.into_inner());
    let line_count = text.lines().count();
    if line_count < threshold || !*PAGER_AVAILABLE {
        print_direct(text);
        return;
    }

    let pager_cmd = std::env::var("PAGER").unwrap_or_else(|_| "less".to_string());
    let pager_parts: Vec<&str> = pager_cmd.split_whitespace().collect();
    let mut child = match Command::new(pager_parts.first().copied().unwrap_or("less"))
        .args(&pager_parts[1..])
        .args(pager_args(&pager_cmd))
        .stdin(Stdio::piped())
        .stdout(Stdio::inherit())
        .stderr(Stdio::null())
        .spawn()
    {
        Ok(c) => c,
        Err(_) => {
            print_direct(text);
            return;
        }
    };

    if let Some(mut stdin) = child.stdin.take() {
        let _ = stdin.write_all(text.as_bytes());
    }

    let _ = child.wait();
}

fn pager_args(cmd: &str) -> Vec<&str> {
    let binary_name = cmd.rsplit('/').next().unwrap_or(cmd);
    if binary_name == "less" || binary_name == "busybox" || cmd.contains("busybox") {
        vec!["-R", "-F", "-X"]
    } else {
        vec![]
    }
}

/// Cached result of checking whether a pager is available on this system.
static PAGER_AVAILABLE: LazyLock<bool> = LazyLock::new(|| {
    let pager_cmd = std::env::var("PAGER").unwrap_or_else(|_| "less".to_string());
    let pager_parts: Vec<&str> = pager_cmd.split_whitespace().collect();
    // Use --help which most pagers support (more portable than --version)
    Command::new(pager_parts.first().copied().unwrap_or("less"))
        .args(&pager_parts[1..])
        .arg("--help")
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .is_ok()
});

fn print_direct(text: &str) {
    if text.ends_with('\n') {
        print!("{text}");
    } else {
        println!("{text}");
    }
    let _ = std::io::stdout().flush();
}

