use std::sync::LazyLock;

use serde::{Deserialize, Serialize};

/// Effort level for reasoning models (OpenAI o1/o3).
#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
pub enum ReasoningEffort {
    Low,
    Medium,
    High,
}

impl ReasoningEffort {
    pub fn as_str(&self) -> &'static str {
        match self {
            ReasoningEffort::Low => "low",
            ReasoningEffort::Medium => "medium",
            ReasoningEffort::High => "high",
        }
    }

    pub fn from_str(s: &str) -> Self {
        match s.to_lowercase().as_str() {
            "low" => ReasoningEffort::Low,
            "high" => ReasoningEffort::High,
            _ => ReasoningEffort::Medium,
        }
    }
}

/// Configuration for thinking/reasoning models.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub struct ReasoningConfig {
    /// Whether to enable reasoning/thinking mode.
    pub enabled: bool,
    /// Reasoning effort for OpenAI o1/o3 (low/medium/high).
    pub effort: ReasoningEffort,
    /// Token budget for Anthropic extended thinking.
    pub thinking_budget: u32,
    /// Whether to show the reasoning trace to the user.
    pub show_reasoning: bool,
}

impl Default for ReasoningConfig {
    fn default() -> Self {
        Self {
            enabled: false,
            effort: ReasoningEffort::Medium,
            thinking_budget: 8192,
            show_reasoning: false,
        }
    }
}

static REASONING_OVERRIDE: LazyLock<std::sync::RwLock<Option<bool>>> = LazyLock::new(|| std::sync::RwLock::new(None));

#[allow(dead_code)]
pub fn set_reasoning_override(enabled: Option<bool>) {
    let mut w = REASONING_OVERRIDE.write().unwrap_or_else(|e| e.into_inner());
    *w = enabled;
}

pub fn is_reasoning_model(model: &str) -> bool {
    if let Some(override_val) = *REASONING_OVERRIDE.read().unwrap_or_else(|e| e.into_inner()) {
        return override_val;
    }
    let lower = model.to_lowercase();
    lower == "o1"
        || lower.starts_with("o1-")
        || lower.starts_with("o3-")
        || lower.contains("deepseek-r1")
        || (lower.contains("claude-sonnet-4-20") && lower.contains("thinking"))
        || lower.contains("-thinking")
        || lower.starts_with("thinking")
}

/// Detects if a model requires disabling streaming (e.g., o1-preview).
pub fn requires_non_streaming(model: &str) -> bool {
    let lower = model.to_lowercase();
    lower == "o1-preview" || lower == "o1-mini"
}

/// Checks if a model does NOT support system prompts.
/// Only o1-preview and o1-mini lack system prompt support;
/// newer o1 models (e.g. o1-2024-12-17) and o3-mini support it.
pub fn system_prompt_not_supported(model: &str) -> bool {
    let lower = model.to_lowercase();
    lower == "o1-preview" || lower == "o1-mini"
}

