//! Text and string utility functions.
//! Provides human-readable sizes, byte-safe truncation, line truncation,
//! and timestamp formatting for display purposes.

/// Formats byte counts as human-readable strings (e.g., `1.5K`, `3.2M`).
pub(crate) fn human_size(bytes: u64) -> String {
    if bytes < 1024 {
        bytes.to_string()
    } else if bytes < 1024 * 1024 {
        let b = bytes as f64 / 1024.0;
        format!("{:.1}K", if b > 9999.9 { 9999.9 } else { b })
    } else {
        let b = bytes as f64 / (1024.0 * 1024.0);
        format!("{:.1}M", if b > 9999.9 { 9999.9 } else { b })
    }
}

/// Truncates a string to at most `max` bytes, preserving char boundaries.
pub(crate) fn truncate_bytes(s: &str, max: usize) -> String {
    if s.is_empty() || max == 0 {
        return String::new();
    }
    if s.len() <= max {
        return s.to_string();
    }
    let mut end = max;
    while !s.is_char_boundary(end) {
        end -= 1;
    }
    if end == 0 {
        return "[truncated]".to_string();
    }
    format!("{}\n...[truncated]", &s[..end])
}

/// Truncates a string to at most `max_lines` lines.
pub(crate) fn truncate_to_lines(s: &str, max_lines: usize) -> String {
    let total = s.lines().count();
    let mut result: String = s.lines().take(max_lines).collect::<Vec<_>>().join("\n");
    if total > max_lines {
        result.push_str("\n...[truncated]");
    }
    result
}

/// Converts a Unix day count to a year, returning the year and remaining days.
/// Uses arithmetic with 400-year cycle blocks for O(1) performance.
fn days_to_year(days: i64) -> (i64, i64) {
    let mut y = 1970i64;
    let mut d = days;
    const DAYS_IN_400_YEARS: i64 = 146097;
    if d >= DAYS_IN_400_YEARS {
        let blocks = d / DAYS_IN_400_YEARS;
        y += blocks * 400;
        d -= blocks * DAYS_IN_400_YEARS;
    }
    while d >= 365 {
        let year_days = if (y % 4 == 0 && y % 100 != 0) || y % 400 == 0 {
            366
        } else {
            365
        };
        if d < year_days {
            break;
        }
        d -= year_days;
        y += 1;
    }
    (y, d)
}

/// Returns the current year.
pub(crate) fn current_year() -> i64 {
    let dur = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default();
    let days = (dur.as_secs() / 86400) as i64;
    days_to_year(days).0
}

/// Returns the current UTC timestamp as `YYYY-MM-DD HH:MM:SS`.
pub(crate) fn format_timestamp() -> String {
    let dur = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default();
    let total_secs = dur.as_secs();

    let days = total_secs / 86400;
    let time_secs = total_secs % 86400;
    let hours = time_secs / 3600;
    let minutes = (time_secs % 3600) / 60;

    let seconds = time_secs % 60;

    let (y, d) = days_to_year(days as i64);
    let is_leap = (y % 4 == 0 && y % 100 != 0) || y % 400 == 0;
    let month_days = [
        31u64,
        if is_leap { 29 } else { 28 },
        31,
        30,
        31,
        30,
        31,
        31,
        30,
        31,
        30,
        31,
    ];
    let mut month = 1usize;
    let mut day = d as u64; // remaining days within year
    for &md in &month_days {
        if day < md {
            break;
        }
        day -= md;
        month += 1;
    }
    format!(
        "{:04}-{:02}-{:02} {:02}:{:02}:{:02}",
        y,
        month,
        day + 1,
        hours,
        minutes,
        seconds
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn truncates_string() {
        let out = truncate_bytes("abcdef", 3);
        assert!(out.starts_with("abc"));
    }

    #[test]
    fn human_size_works() {
        assert_eq!(human_size(500), "500");
        assert_eq!(human_size(2048), "2.0K");
        assert_eq!(human_size(5_242_880), "5.0M");
    }

    #[test]
    fn truncate_to_lines_limits_lines() {
        let input = "line1\nline2\nline3\nline4";
        let out = truncate_to_lines(input, 2);
        assert_eq!(out.lines().count(), 3);
        assert!(out.ends_with("[truncated]"));
    }

    #[test]
    fn truncate_to_lines_passes_short() {
        let input = "short";
        let out = truncate_to_lines(input, 10);
        assert_eq!(out, "short");
    }

    #[test]
    fn format_timestamp_returns_valid_format() {
        let ts = format_timestamp();
        assert_eq!(ts.len(), 19);
        assert!(ts.chars().nth(4) == Some('-'));
        assert!(ts.chars().nth(7) == Some('-'));
    }

    #[test]
    fn truncate_bytes_preserves_char_boundaries() {
        let s = "Hell\u{00e9} world";
        let out = truncate_bytes(s, 5);
        assert_eq!(out, "Hell\n...[truncated]");
        assert!(!out.contains('\u{00e9}'));
    }

    #[test]
    fn prop_truncate_bytes_never_exceeds_limit() {
        proptest::proptest!(|(s: String, limit in 0usize..1000)| {
            let result = truncate_bytes(&s, limit);
            // The truncated suffix "\n...[truncated]" is 14 bytes,
            // but we bound by limit + 20 for a reasonable upper bound.
            assert!(result.len() <= limit + 20,
                "truncate_bytes({}, {}) = {} (len {})",
                s, limit, result, result.len());
        });
    }

    #[test]
    fn prop_truncate_bytes_preserves_prefix() {
        proptest::proptest!(|(s: String, limit in 10usize..500usize)| {
            let result = truncate_bytes(&s, limit);
            if s.is_empty() {
                assert_eq!(result, "", "empty string should return empty");

            } else if s.len() > limit {
                assert!(result.contains("[truncated]"), "result should indicate truncation");
                if result != "[truncated]" {
                    let suffix = "\n...[truncated]";
                    let prefix = &result[..result.len() - suffix.len()];
                    assert!(s.starts_with(prefix),
                        "truncated result should be a prefix of original");
                }
            } else {
                assert_eq!(result, s, "result should equal original when under limit");
            }
        });
    }

    #[test]
    fn prop_human_size_never_empty() {
        proptest::proptest!(|(bytes: u64)| {
            let result = human_size(bytes);
            assert!(!result.is_empty(), "human_size({}) should not be empty", bytes);
            assert!(result.len() < 20, "human_size({}) = '{}' should be compact", bytes, result);
        });
    }

    #[test]
    fn prop_truncate_to_lines_respects_limit() {
        proptest::proptest!(|(lines in proptest::collection::vec("[a-z]{0,20}", 0..50), max_lines in 1usize..20usize)| {
            let text = lines.join("\n");
            let result = truncate_to_lines(&text, max_lines);
            let result_lines = result.lines().count();
            // May have +1 for the "[truncated]" line
            assert!(result_lines <= max_lines + 1,
                "truncate_to_lines with max_lines={} returned {} lines", max_lines, result_lines);
        });
    }
}

use std::sync::LazyLock;

static BPE_CL100K: LazyLock<Option<tiktoken_rs::CoreBPE>> = LazyLock::new(|| tiktoken_rs::cl100k_base().ok());
#[allow(dead_code)]
static BPE_O200K: LazyLock<Option<tiktoken_rs::CoreBPE>> = LazyLock::new(|| tiktoken_rs::o200k_base().ok());

#[allow(dead_code)]
pub fn get_tokenizer(model: &str) -> &'static Option<tiktoken_rs::CoreBPE> {
    let lower = model.to_lowercase();
    if lower.contains("gpt-4o") || lower.contains("o1") || lower.contains("o3") {
        &BPE_O200K
    } else {
        &BPE_CL100K
    }
}

/// Estimates token count, using tiktoken-rs if available, falling back to heuristic.
pub fn estimate_tokens(text: &str) -> usize {
    if text.is_empty() {
        return 0;
    }
    if let Some(ref bpe) = *BPE_CL100K {
        let tokens = bpe.encode_with_special_tokens(text);
        return tokens.len().max(1);
    }
    estimate_tokens_heuristic(text)
}

#[allow(dead_code)]
pub fn estimate_tokens_for_model(text: &str, model: &str) -> usize {
    if text.is_empty() {
        return 0;
    }
    if let Some(ref bpe) = *get_tokenizer(model) {
        let tokens = bpe.encode_with_special_tokens(text);
        return tokens.len().max(1);
    }
    estimate_tokens_heuristic(text)
}

fn estimate_tokens_heuristic(text: &str) -> usize {
    let bytes = text.len();
    let mut cjk_chars = 0usize;
    let mut other_unicode = 0usize;

    for c in text.chars() {
        let cp = c as u32;
        if c.is_ascii_whitespace() {
            continue;
        }
        if (0x4E00..=0x9FFF).contains(&cp)
            || (0x3400..=0x4DBF).contains(&cp)
            || (0x2E80..=0x2EFF).contains(&cp)
            || (0x3000..=0x303F).contains(&cp)
            || (0xF900..=0xFAFF).contains(&cp)
            || (0xFF00..=0xFFEF).contains(&cp)
        {
            cjk_chars += 1;
        } else if !c.is_ascii() {
            other_unicode += 1;
        }
    }

    let ascii_bytes = bytes - cjk_chars * 3 - other_unicode * 2;
    let ascii_tokens = if ascii_bytes > 0 {
        (ascii_bytes as f64 / 3.5).round() as usize
    } else {
        0
    };

    let total = ascii_tokens + cjk_chars + other_unicode * 2;
    total.max(1)
}

pub fn estimate_tokens_batch(texts: &[&str]) -> usize {
    texts.iter().map(|t| estimate_tokens(t)).sum()
}

pub fn context_usage_percent(used: usize, limit: usize) -> f64 {
    if limit == 0 {
        return 0.0;
    }
    (used as f64 / limit as f64 * 100.0).min(100.0)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn empty_input_returns_zero() {
        assert_eq!(estimate_tokens(""), 0);
    }

    #[test]
    fn single_char_returns_at_least_one() {
        assert!(estimate_tokens("a") >= 1);
    }

    #[test]
    fn short_text_returns_positive() {
        assert!(estimate_tokens("hello world") >= 1);
    }

    #[test]
    fn cjk_characters_count_as_one() {
        let cjk = estimate_tokens("你好世界");
        let ascii = estimate_tokens("hello world a b c d");
        assert!(cjk <= ascii);
    }

    #[test]
    fn batch_counts_total() {
        let total = estimate_tokens_batch(&["hello", "world", "test"]);
        assert!(total > 0);
    }
}

use std::path::PathBuf;
use std::sync::{Arc, Mutex};
use std::time::Duration;

use tokio::time::timeout;

use crate::agentic::{run_lint, run_test};
use crate::blocklist::is_command_blocked;
use crate::find::{find_matches, FindOptions};
use crate::provider::tools::{builtin_tools, ToolCall, ToolResponse, ToolResult as ToolCallResult};
use crate::provider::Provider;
