const DEFAULT_THEME_NAME: &str = "GHOST";

/// Returns true if NO_COLOR or CLICOLOR=0 is set (disables ANSI output).
/// Result is cached on first call since environment variables don't change at runtime.
fn no_color() -> bool {
    static CACHE: OnceLock<bool> = OnceLock::new();
    *CACHE.get_or_init(|| {
        std::env::var("NO_COLOR").is_ok() || std::env::var("CLICOLOR").map(|v| v == "0").unwrap_or(false)
    })
}

/// Custom theme definition for loading from TOML files.
#[derive(Debug, serde::Deserialize)]
struct CustomThemeDef {
    name: String,
    bg: String,
    surface: String,
    border: String,
    accent: String,
    accent_dim: String,
    accent_info: String,
    text_muted: String,
    text_faint: String,
    text_bright: String,
    pill_bg: String,
    pill_border: String,
    pill_text: String,
    kbd_bg: String,
    kbd_border: String,
    kbd_text: String,
    sys_color: String,
    sel_bg: String,
    sel_left: String,
    cursor: String,
    error: String,
    success: String,
    code_bg: String,
}

static CUSTOM_THEMES: LazyLock<Mutex<BTreeMap<String, Theme>>> = LazyLock::new(|| Mutex::new(BTreeMap::new()));
static CUSTOM_THEMES_LOADED: AtomicBool = AtomicBool::new(false);

/// Loads a custom theme from a TOML file.
fn load_custom_theme(path: &PathBuf) -> Option<(String, Theme)> {
    let text = std::fs::read_to_string(path).ok()?;
    let def: CustomThemeDef = toml::from_str(&text).ok()?;
    let theme = Theme::build(
        &def.name,
        &def.bg,
        &def.surface,
        &def.border,
        &def.accent,
        &def.accent_dim,
        &def.accent_info,
        &def.text_muted,
        &def.text_faint,
        &def.text_bright,
        &def.pill_bg,
        &def.pill_border,
        &def.pill_text,
        &def.kbd_bg,
        &def.kbd_border,
        &def.kbd_text,
        &def.sys_color,
        &def.sel_bg,
        &def.sel_left,
        &def.cursor,
        &def.error,
        &def.success,
        &def.code_bg,
    );
    Some((def.name.to_uppercase(), theme))
}

/// Loads all custom themes from `~/.config/rem-cli/themes/`.
fn load_custom_themes() {
    if CUSTOM_THEMES_LOADED.swap(true, Ordering::SeqCst) {
        return;
    }
    let theme_dir = dirs::home_dir().map(|h| h.join(".config/rem-cli/themes"));
    let Some(dir) = theme_dir else { return };
    if !dir.exists() {

        Theme::build(
            "CONTRAST", "#ffffff", "#f0f0f0", "#d0d0d0", "#000000", "#333333", "#0055aa", "#666666", "#999999",
            "#808080", "#e8e8e8", "#cccccc", "#000000", "#ffffff", "#d0d0d0", "#666666", "#e0e0e0", "#000000",
            "#000000", "#cc0000", "#008800", "#f8f8f8", "#f0f0f0",
        ),
    );
    t
});

static ACTIVE_THEME: LazyLock<RwLock<Arc<Theme>>> = LazyLock::new(|| {
    let theme = by_name(DEFAULT_THEME_NAME);
    RwLock::new(Arc::new(theme))
});

/// Converts a hex color string to an ANSI foreground escape code.
fn hex_to_ansi_fg(hex: &str) -> String {
    if hex.as_bytes().first() != Some(&b'#') || hex.len() != 7 {
        return String::new();
    }
    let r = u8::from_str_radix(&hex[1..3], 16).unwrap_or(0);
    let g = u8::from_str_radix(&hex[3..5], 16).unwrap_or(0);
    let b = u8::from_str_radix(&hex[5..7], 16).unwrap_or(0);
    let mut buf = String::with_capacity(20);
    use std::fmt::Write;
    let _ = write!(buf, "\x1b[38;2;{r};{g};{b}m");
    buf
}

/// Converts a hex color string to an ANSI background escape code.
fn hex_to_ansi_bg(hex: &str) -> String {
    if hex.as_bytes().first() != Some(&b'#') || hex.len() != 7 {
        return String::new();
    }
    let r = u8::from_str_radix(&hex[1..3], 16).unwrap_or(0);
    let g = u8::from_str_radix(&hex[3..5], 16).unwrap_or(0);
    let b = u8::from_str_radix(&hex[5..7], 16).unwrap_or(0);
    let mut buf = String::with_capacity(20);
    use std::fmt::Write;
    let _ = write!(buf, "\x1b[48;2;{r};{g};{b}m");
    buf
}

